INSERT INTO node_properties (id, node_id, name, value_type, string_value, date_value, ref_node_id) VALUES
('d2000000-0003-0000-0000-000000000001', 'd2000000-0001-0000-0000-000000000001', 'description', 'STRING', 'Plus grande famille linguistique d''Afrique avec plus de 1500 langues. Couvre l''Afrique subsaharienne du Sénégal au Kenya', NULL, NULL),
('d2000000-0003-0000-0000-000000000002', 'd2000000-0001-0000-0000-000000000001', 'nombre_de_langues', 'STRING', 'Plus de 1500 langues', NULL, NULL),
('d2000000-0003-0000-0000-000000000003', 'd2000000-0001-0000-0000-000000000001', 'locuteurs', 'STRING', 'Plus de 700 millions de personnes', NULL, NULL),
('d2000000-0003-0000-0000-000000000004', 'd2000000-0001-0000-0000-000000000002', 'description', 'STRING', 'Famille linguistique couvrant le Nord de l''Afrique, la Corne de l''Afrique et le Moyen-Orient. Comprend l''arabe, l''amharique et le berbère', NULL, NULL),
('d2000000-0003-0000-0000-000000000005', 'd2000000-0001-0000-0000-000000000002', 'nombre_de_langues', 'STRING', 'Plus de 400 langues', NULL, NULL),
('d2000000-0003-0000-0000-000000000006', 'd2000000-0001-0000-0000-000000000002', 'locuteurs', 'STRING', 'Plus de 500 millions de personnes', NULL, NULL),
('d2000000-0003-0000-0000-000000000007', 'd2000000-0001-0000-0000-000000000003', 'description', 'STRING', 'Famille linguistique dispersée du Mali au Soudan et jusqu''en Tanzanie. Comprend les langues des peuples Nilotiques comme le Dinka et le Maasai', NULL, NULL),
('d2000000-0003-0000-0000-000000000008', 'd2000000-0001-0000-0000-000000000003', 'nombre_de_langues', 'STRING', 'Environ 200 langues', NULL, NULL),
('d2000000-0003-0000-0000-000000000009', 'd2000000-0001-0000-0000-000000000004', 'description', 'STRING', 'Famille linguistique des peuples les plus anciens d''Afrique. Caractérisée par l''utilisation de clics comme consonnes. Présente en Afrique australe', NULL, NULL),
('d2000000-0003-0000-0000-000000000010', 'd2000000-0001-0000-0000-000000000004', 'nombre_de_langues', 'STRING', 'Environ 30 langues', NULL, NULL),
('d2000000-0003-0000-0000-000000000011', 'd2000000-0001-0000-0000-000000000006', 'description', 'STRING', 'Sous-famille du Niger-Congo avec plus de 500 langues. Langues parlées par les peuples issus de la migration Bantou en Afrique centrale, orientale et australe', NULL, NULL),
('d2000000-0003-0000-0000-000000000012', 'd2000000-0001-0000-0000-000000000007', 'description', 'STRING', 'Sous-famille du Niger-Congo, langues du Sahel occidental. Comprend le Bambara, le Dioula et le Soninké', NULL, NULL),
('d2000000-0003-0000-0000-000000000013', 'd2000000-0001-0000-0000-000000000008', 'description', 'STRING', 'Sous-famille du Niger-Congo en Afrique de l''Ouest côtière. Comprend le Yoruba, l''Igbo et l''Akan', NULL, NULL),
('d2000000-0003-0000-0000-000000000014', 'd2000000-0001-0000-0000-000000000014', 'description', 'STRING', 'Langue bantoue parlée en RDC, Congo-Brazzaville et Angola. Lingua franca de l''Afrique centrale avec plus de 40 millions de locuteurs', NULL, NULL),
('d2000000-0003-0000-0000-000000000015', 'd2000000-0001-0000-0000-000000000014', 'locuteurs', 'STRING', '40 millions', NULL, NULL),
('d2000000-0003-0000-0000-000000000016', 'd2000000-0001-0000-0000-000000000015', 'description', 'STRING', 'Langue bantoue et lingua franca de l''Afrique de l''Est. Langue officielle de la Tanzanie, du Kenya et de l''Ouganda', NULL, NULL),
('d2000000-0003-0000-0000-000000000017', 'd2000000-0001-0000-0000-000000000015', 'locuteurs', 'STRING', '200 millions', NULL, NULL),
('d2000000-0003-0000-0000-000000000018', 'd2000000-0001-0000-0000-000000000019', 'description', 'STRING', 'Langue Kwa parlée par plus de 50 millions de personnes au Nigeria, Bénin et Togo. L''une des langues africaines les plus parlées dans la diaspora', NULL, NULL),
('d2000000-0003-0000-0000-000000000019', 'd2000000-0001-0000-0000-000000000019', 'locuteurs', 'STRING', '50 millions', NULL, NULL),
('d2000000-0003-0000-0000-000000000020', 'd2000000-0001-0000-0000-000000000024', 'description', 'STRING', 'Langue sémitique officielle de l''Ethiopie, parlée par les Amhara. Héritière de l''Guèze, l''ancienne langue liturgique de l''Eglise orthodoxe éthiopienne', NULL, NULL),
('d2000000-0003-0000-0000-000000000021', 'd2000000-0001-0000-0000-000000000024', 'locuteurs', 'STRING', '25 millions', NULL, NULL),
('d2000000-0003-0000-0000-000000000022', 'd2000000-0001-0000-0000-000000000027', 'description', 'STRING', 'Langue tchadique la plus parlée d''Afrique. Lingua franca du Sahel avec plus de 80 millions de locuteurs au Nigeria, Niger et Tchad', NULL, NULL),
('d2000000-0003-0000-0000-000000000023', 'd2000000-0001-0000-0000-000000000027', 'locuteurs', 'STRING', '80 millions', NULL, NULL),
('d2000000-0003-0000-0000-000000000024', 'd2000000-0001-0000-0000-000000000028', 'description', 'STRING', 'Seule langue austronésienne d''Afrique. Apportée par des migrants indonésiens il y a 1500 ans à Madagascar, témoignage unique de la mondialisation antique', NULL, NULL);
